/* ══ Layout: Navigation, Sessions, Model Dropdown, Page Grid ══ */

/* ── Navigation ── */

.nav-panel {
  border-right: 1px solid var(--border);
  background: var(--surface);
  flex-direction: column;
  flex-shrink: 0;
  width: 180px;
  display: flex;
}

.nav-panel.hidden { display: none; }

.nav-link {
  color: var(--muted);
  padding: 8px 16px;
  font-size: 0.85rem;
  text-decoration: none;
  transition: background 0.15s, color 0.15s;
  display: flex;
  align-items: center;
  gap: 8px;
}

.nav-link:hover {
  background: var(--bg-hover);
  color: var(--text);
}

.nav-link.active {
  color: var(--accent);
  background: var(--accent-subtle);
}

.nav-count { display: none; }
.nav-count.visible { display: inline-block; }

/* ── Burger button ── */

.burger-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--muted);
  padding: 4px;
  border-radius: 4px;
  display: flex;
  align-items: center;

